import React, { useCallback, useEffect, useRef, useState } from 'react';
import { addons } from 'storybook/internal/manager-api';
import { useStorybookState } from 'storybook/internal/manager-api';
import { useTheme } from 'storybook/internal/theming';
import { EVENTS } from './constants';
import { useIndexedDB } from './useIndexedDB';
import { CodeMirrorEditor, type CodeMirrorEditorHandle } from './CodeMirrorEditor';
import JSON5 from 'json5';

function idbKeyFor(storyId: string) {
  return `sdui-json-${storyId}`;
}

function getChannel() {
  try { return addons.getChannel(); } catch { return null; }
}

function tryParse(text: string): { parsed: any; error: string | null } {
  try {
    return { parsed: JSON.parse(text), error: null };
  } catch {
    try {
      return { parsed: JSON5.parse(text), error: null };
    } catch (e) {
      return { parsed: null, error: (e as Error).message };
    }
  }
}

export function JsonEditorPanel() {
  const state = useStorybookState();
  const storyId = state.storyId ?? '';
  const theme = useTheme();
  const storedThemePref = typeof localStorage !== 'undefined'
    ? localStorage.getItem('sb-ui-theme')
    : null;
  const isDarkMode = theme.base === 'dark' || storedThemePref === 'dark';

  const [defaultJson, setDefaultJson] = useState<string>('');
  const [text, setText] = useState<string>('');
  const [error, setError] = useState<string | null>(null);
  const [dirty, setDirty] = useState(false);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const editorRef = useRef<CodeMirrorEditorHandle>(null);
  const retryRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const initializedRef = useRef(false);

  const { stored, save, remove, ready } = useIndexedDB(idbKeyFor(storyId));

  useEffect(() => {
    return () => {
      if (debounceRef.current) clearTimeout(debounceRef.current);
      if (retryRef.current) clearInterval(retryRef.current);
    };
  }, []);

  useEffect(() => {
    if (debounceRef.current) {
      clearTimeout(debounceRef.current);
      debounceRef.current = null;
    }
    setDefaultJson('');
    setError(null);
    initializedRef.current = false;
  }, [storyId]);

  useEffect(() => {
    const channel = getChannel();
    if (!channel) return;

    const onSetDefault = (json: string) => {
      setDefaultJson(json);
      if (retryRef.current) {
        clearInterval(retryRef.current);
        retryRef.current = null;
      }
    };

    channel.on(EVENTS.SET_DEFAULT_JSON, onSetDefault);
    channel.emit(EVENTS.REQUEST_DEFAULT);

    let retryCount = 0;
    retryRef.current = setInterval(() => {
      retryCount++;
      if (retryCount > 20) {
        if (retryRef.current) clearInterval(retryRef.current);
        return;
      }
      channel.emit(EVENTS.REQUEST_DEFAULT);
    }, 250);

    return () => {
      channel.off(EVENTS.SET_DEFAULT_JSON, onSetDefault);
      if (retryRef.current) {
        clearInterval(retryRef.current);
        retryRef.current = null;
      }
    };
  }, [storyId]);

  useEffect(() => {
    if (!ready || !defaultJson) return;
    if (initializedRef.current) return;
    initializedRef.current = true;
    const initial = stored ?? defaultJson;
    setText(initial);
    editorRef.current?.setValue(initial);
    setDirty(!!stored);
    setError(null);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [ready, defaultJson, storyId]);

  const handleChange = useCallback(
    (value: string) => {
      setText(value);

      if (debounceRef.current) clearTimeout(debounceRef.current);

      debounceRef.current = setTimeout(() => {
        const { parsed, error: parseErr } = tryParse(value);
        if (parsed !== null) {
          save(value);
          setDirty(true);
          getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
        } else {
          save(value);
          setDirty(true);
        }
      }, 400);
    },
    [save],
  );

  const handleValidationChange = useCallback(
    (hasErrors: boolean, message: string | null) => {
      setError(hasErrors ? message : null);
    },
    [],
  );

  const handleReset = useCallback(() => {
    remove();
    setText(defaultJson);
    editorRef.current?.setValue(defaultJson);
    setDirty(false);
    setError(null);
    const { parsed } = tryParse(defaultJson);
    if (parsed !== null) {
      getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
    }
  }, [defaultJson, remove]);

  const handleFormat = useCallback(() => {
    const currentText = editorRef.current?.getValue() ?? '';
    const { parsed, error: parseErr } = tryParse(currentText);
    if (parsed !== null) {
      const formatted = JSON.stringify(parsed, null, 2);
      setText(formatted);
      editorRef.current?.setValue(formatted);
      save(formatted);
      getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
      setError(null);
    } else {
      setError(parseErr);
    }
  }, [save]);

  const s = isDarkMode ? darkStyles : lightStyles;

  if (!storyId) {
    return <div style={s.empty}>Select a story to edit its JSON.</div>;
  }

  const isWaiting = !defaultJson && !text;

  return (
    <div style={s.container}>
      <div style={s.toolbar}>
        <span style={s.label}>
          SDUI JSON {dirty && <span style={s.badge}>edited</span>}
        </span>
        <div style={s.actions}>
          <button
            style={s.btn}
            onClick={handleFormat}
            title="Format JSON (normalizes to strict JSON)"
          >
            Format
          </button>
          <button
            style={{ ...s.btn, ...(dirty ? s.btnReset : s.btnDisabled) }}
            onClick={handleReset}
            disabled={!dirty}
            title="Reset to story default"
          >
            Reset
          </button>
        </div>
      </div>

      {error && !isWaiting && <div style={s.error}>{error}</div>}

      {isWaiting ? (
        <div style={s.empty}>
          Waiting for story to send SDUI JSON…
          <br />
          <span style={{ fontSize: 11, opacity: 0.7 }}>
            If this persists, the current story may not use useSDUIJsonEditor().
          </span>
        </div>
      ) : (
        <div style={s.editorContainer}>
          <CodeMirrorEditor
            ref={editorRef}
            value={text}
            onChange={handleChange}
            onValidationChange={handleValidationChange}
            isDarkMode={isDarkMode}
          />
        </div>
      )}
    </div>
  );
}

const lightStyles: Record<string, React.CSSProperties> = {
  container: {
    display: 'flex',
    flexDirection: 'column',
    height: '100%',
    fontFamily:
      "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif",
    fontSize: 12,
  },
  toolbar: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '6px 10px',
    borderBottom: '1px solid #e0e0e0',
    background: '#fafafa',
    flexShrink: 0,
  },
  label: {
    fontWeight: 600,
    fontSize: 12,
    color: '#333',
    letterSpacing: '0.5px',
    textTransform: 'uppercase' as const,
  },
  badge: {
    display: 'inline-block',
    marginLeft: 6,
    padding: '1px 6px',
    borderRadius: 4,
    background: '#ff9800',
    color: '#fff',
    fontSize: 10,
    fontWeight: 700,
    textTransform: 'none' as const,
  },
  actions: {
    display: 'flex',
    gap: 6,
  },
  btn: {
    padding: '3px 10px',
    borderRadius: 4,
    border: '1px solid #ccc',
    background: '#fff',
    cursor: 'pointer',
    fontSize: 11,
    color: '#333',
    fontWeight: 500,
    transition: 'background 0.15s, border-color 0.15s',
  },
  btnReset: {
    borderColor: '#ff5722',
    color: '#ff5722',
  },
  btnDisabled: {
    opacity: 0.4,
    cursor: 'not-allowed',
  },
  error: {
    padding: '6px 10px',
    background: '#ffebee',
    color: '#c62828',
    fontSize: 12,
    borderBottom: '1px solid #ef9a9a',
    flexShrink: 0,
  },
  editorContainer: {
    flex: 1,
    overflow: 'hidden',
  },
  empty: {
    padding: 20,
    color: '#999',
    textAlign: 'center' as const,
  },
};

const darkStyles: Record<string, React.CSSProperties> = {
  container: {
    display: 'flex',
    flexDirection: 'column',
    height: '100%',
    fontFamily:
      "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif",
    fontSize: 12,
    background: '#1e1e1e',
    color: '#d4d4d4',
  },
  toolbar: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '6px 10px',
    borderBottom: '1px solid #3c3c3c',
    background: '#252526',
    flexShrink: 0,
  },
  label: {
    fontWeight: 600,
    fontSize: 12,
    color: '#d4d4d4',
    letterSpacing: '0.5px',
    textTransform: 'uppercase' as const,
  },
  badge: {
    display: 'inline-block',
    marginLeft: 6,
    padding: '1px 6px',
    borderRadius: 4,
    background: '#e2a308',
    color: '#1e1e1e',
    fontSize: 10,
    fontWeight: 700,
    textTransform: 'none' as const,
  },
  actions: {
    display: 'flex',
    gap: 6,
  },
  btn: {
    padding: '3px 10px',
    borderRadius: 4,
    border: '1px solid #555',
    background: '#3c3c3c',
    cursor: 'pointer',
    fontSize: 11,
    color: '#d4d4d4',
    fontWeight: 500,
    transition: 'background 0.15s, border-color 0.15s',
  },
  btnReset: {
    borderColor: '#ff6e40',
    color: '#ff6e40',
  },
  btnDisabled: {
    opacity: 0.4,
    cursor: 'not-allowed',
  },
  error: {
    padding: '6px 10px',
    background: '#4a1e1e',
    color: '#f48771',
    fontSize: 12,
    borderBottom: '1px solid #6e3333',
    flexShrink: 0,
  },
  editorContainer: {
    flex: 1,
    overflow: 'hidden',
  },
  empty: {
    padding: 20,
    color: '#858585',
    textAlign: 'center' as const,
  },
};

