          return [{ from, to, severity: 'error', message: msg, source: 'json5' }];
        }
      },
      { delay: 300 },
    );

    const schemaLinter = linter(sduiSchemaLinter, { delay: 500 });

    const updateListener = EditorView.updateListener.of(update => {
      if (update.docChanged && !isExternalUpdate.current) {
        const doc = update.state.doc.toString();
        onChangeRef.current(doc);
      }
    });

    const initialTheme = isDarkMode ? darkTheme : lightTheme;
    const initialHighlight = isDarkMode
      ? syntaxHighlighting(darkHighlightStyle)
      : syntaxHighlighting(defaultHighlightStyle, { fallback: true });

    const state = EditorState.create({
      doc: value,
      extensions: [
        lineNumbers(),
        highlightActiveLineGutter(),
        highlightActiveLine(),
        drawSelection(),
        rectangularSelection(),
        bracketMatching(),
        foldGutter(),
        highlightSelectionMatches(),
        history(),
        javascript(),
        highlightCompartment.of(initialHighlight),
        lintGutter(),
        json5ParseLinter,
        schemaLinter,
        themeCompartment.of(initialTheme),
        updateListener,
        keymap.of([
          ...defaultKeymap,
          ...historyKeymap,
          ...foldKeymap,
          ...searchKeymap,
          indentWithTab,
        ]),
        EditorView.lineWrapping,
        EditorState.tabSize.of(2),
      ],
    });

    const view = new EditorView({
      state,
      parent: containerRef.current,
    });

    viewRef.current = view;

    return () => {
      view.destroy();
      viewRef.current = null;
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    const view = viewRef.current;
    if (!view) return;

    const newTheme = isDarkMode ? darkTheme : lightTheme;
    const newHighlight = isDarkMode
      ? syntaxHighlighting(darkHighlightStyle)
      : syntaxHighlighting(defaultHighlightStyle, { fallback: true });

    view.dispatch({
      effects: [
        themeCompartment.reconfigure(newTheme),
        highlightCompartment.reconfigure(newHighlight),
      ],
    });
  }, [isDarkMode, themeCompartment, highlightCompartment]);

  useEffect(() => {
    const view = viewRef.current;
    if (!view) return;
    const currentDoc = view.state.doc.toString();
    if (currentDoc !== value) {
      isExternalUpdate.current = true;
      view.dispatch({
        changes: { from: 0, to: view.state.doc.length, insert: value },
      });
      isExternalUpdate.current = false;
    }
  }, [value]);

  return (
    <div
      ref={containerRef}
      style={{ height: '100%', overflow: 'hidden' }}
    />
  );
});

