 1→import { useCallback, useEffect, useRef, useState } from 'react';
 2→import { IDB_NAME, IDB_STORE, IDB_VERSION } from './constants';
 3→
 4→function openDB(): Promise<IDBDatabase> {
 5→  return new Promise((resolve, reject) => {
 6→    const request = indexedDB.open(IDB_NAME, IDB_VERSION);
 7→    request.onupgradeneeded = () => {
 8→      const db = request.result;
 9→      if (!db.objectStoreNames.contains(IDB_STORE)) {
10→        db.createObjectStore(IDB_STORE);
11→      }
12→    };
13→    request.onsuccess = () => resolve(request.result);
14→    request.onerror = () => reject(request.error);
15→  });
16→}
17→
18→function idbGet(db: IDBDatabase, key: string): Promise<string | undefined> {
19→  return new Promise((resolve, reject) => {
20→    const tx = db.transaction(IDB_STORE, 'readonly');
21→    const store = tx.objectStore(IDB_STORE);
22→    const req = store.get(key);
23→    req.onsuccess = () => resolve(req.result as string | undefined);
24→    req.onerror = () => reject(req.error);
25→  });
26→}
27→
28→function idbPut(db: IDBDatabase, key: string, value: string): Promise<void> {
29→  return new Promise((resolve, reject) => {
30→    const tx = db.transaction(IDB_STORE, 'readwrite');
31→    const store = tx.objectStore(IDB_STORE);
32→    const req = store.put(value, key);
33→    req.onsuccess = () => resolve();
34→    req.onerror = () => reject(req.error);
35→  });
36→}
37→
38→function idbDelete(db: IDBDatabase, key: string): Promise<void> {
39→  return new Promise((resolve, reject) => {
40→    const tx = db.transaction(IDB_STORE, 'readwrite');
41→    const store = tx.objectStore(IDB_STORE);
42→    const req = store.delete(key);
43→    req.onsuccess = () => resolve();
44→    req.onerror = () => reject(req.error);
45→  });
46→}
47→
48→export function useIndexedDB(key: string) {
49→  const dbRef = useRef<IDBDatabase | null>(null);
50→  const [stored, setStored] = useState<string | null>(null);
51→  const [ready, setReady] = useState(false);
52→
53→  useEffect(() => {
54→    let cancelled = false;
55→    openDB()
56→      .then(db => {
57→        if (cancelled) { db.close(); return; }
58→        dbRef.current = db;
59→        return idbGet(db, key);
60→      })
61→      .then(val => {
62→        if (!cancelled) {
63→          setStored(val ?? null);
64→          setReady(true);
65→        }
66→      })
67→      .catch(() => {
68→        if (!cancelled) setReady(true);
69→      });
70→    return () => {
71→      cancelled = true;
72→      if (dbRef.current) { dbRef.current.close(); dbRef.current = null; }
73→    };
74→  }, [key]);
75→
76→  const save = useCallback(
