import React, { useState } from 'react';
import { View, ScrollView, Pressable } from 'react-native';
import { Text, Box, SeparatorHorizontal } from '@semparar/design-system-app';
import type { Meta, StoryObj } from 'storybook/internal/types';
import { ScreenRenderer } from '../services/sdui/renderer';
import { registerAllAdapters } from '../services/sdui/adapters';
import type { SDUIScreen } from '../services/sdui/models';
import { useSDUIJsonEditor } from '../../.storybook/addons/json-editor';
import {
  voucherFormAbastecimento,
  voucherFormEstacionamento,
  voucherSummaryAbastecimento,
  voucherSummaryEstacionamento,
  voucherConclusionAbastecimento,
  voucherConclusionEstacionamento,
  voucherRulesAbastecimento,
  voucherRulesEstacionamento,
} from '../services/sdui/mocks';

registerAllAdapters();

type Product = 'Abastecimento' | 'Estacionamento';
const PRODUCTS: Product[] = ['Abastecimento', 'Estacionamento'];

interface ProductToggleProps {
  selected: Product;
  onSelect: (p: Product) => void;
}

function ProductToggle({ selected, onSelect }: ProductToggleProps) {
  return (
    <View style={{ flexDirection: 'row', gap: 8, marginBottom: 16 }}>
      {PRODUCTS.map(p => (
        <Pressable
          key={p}
          onPress={() => onSelect(p)}
          style={{
            paddingHorizontal: 16,
            paddingVertical: 8,
            borderRadius: 20,
            backgroundColor: selected === p ? '#6B2FBE' : '#E8E0F0',
          }}
        >
          <Text
            type="paragraphMDM"
            color={selected === p ? 'LIGHT_BASE_01' : 'INTENSE_COLOR_05'}
          >
            {p}
          </Text>
        </Pressable>
      ))}
    </View>
  );
}

interface ScreenPair {
  Abastecimento: SDUIScreen;
  Estacionamento: SDUIScreen;
}

const SCREEN_PAIRS: Record<string, ScreenPair> = {
  Form: {
    Abastecimento: voucherFormAbastecimento,
    Estacionamento: voucherFormEstacionamento,
  },
  Summary: {
    Abastecimento: voucherSummaryAbastecimento,
    Estacionamento: voucherSummaryEstacionamento,
  },
  Conclusion: {
    Abastecimento: voucherConclusionAbastecimento,
    Estacionamento: voucherConclusionEstacionamento,
  },
  Rules: {
    Abastecimento: voucherRulesAbastecimento,
    Estacionamento: voucherRulesEstacionamento,
  },
};

const SCREEN_NAMES = Object.keys(SCREEN_PAIRS);

function ScreenWithToggle({ pair, title }: { pair: ScreenPair; title: string }) {
  const [product, setProduct] = useState<Product>('Abastecimento');
  const screen = useSDUIJsonEditor(pair[product]);

  return (
    <View style={{ padding: 24, maxWidth: 420 }}>
      <Text type="headingMDL" mb="nano">
        {title}
      </Text>
      <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
        Toggle product or edit the JSON Editor panel below to see live changes.
      </Text>

      <ProductToggle selected={product} onSelect={setProduct} />

      <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm">
        <ScreenRenderer screen={screen} />
      </Box>
    </View>
  );
}

function VoucherFormDemo() {
  return <ScreenWithToggle pair={SCREEN_PAIRS.Form} title="Voucher Form" />;
}

function VoucherSummaryDemo() {
  return (
    <ScreenWithToggle pair={SCREEN_PAIRS.Summary} title="Voucher Summary" />
  );
}

function VoucherConclusionDemo() {
  return (
    <ScreenWithToggle
      pair={SCREEN_PAIRS.Conclusion}
      title="Voucher Conclusion"
    />
  );
}

function VoucherRulesDemo() {
  return <ScreenWithToggle pair={SCREEN_PAIRS.Rules} title="Voucher Rules" />;
}

function FullFlowDemo() {
  const [product, setProduct] = useState<Product>('Abastecimento');
  const [step, setStep] = useState(0);
  const currentName = SCREEN_NAMES[step];
  const screen = useSDUIJsonEditor(SCREEN_PAIRS[currentName][product]);

  return (
    <ScrollView style={{ flex: 1 }}>
      <View style={{ padding: 24, maxWidth: 420 }}>
        <Text type="headingMDL" mb="nano">
          SDUI Spike — Full Voucher Flow
        </Text>
        <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
          Same ScreenRenderer, same adapters — only the JSON changes.
        </Text>

        <ProductToggle selected={product} onSelect={setProduct} />

        <View style={{ flexDirection: 'row', gap: 8, marginBottom: 16 }}>
          {SCREEN_NAMES.map((name, idx) => (
            <Pressable
              key={name}
              onPress={() => setStep(idx)}
              style={{
                paddingHorizontal: 12,
                paddingVertical: 6,
                borderRadius: 8,
                backgroundColor: step === idx ? '#1A1A2E' : '#F0F0F5',
              }}
            >
              <Text
                type={step === idx ? 'paragraphMDM' : 'paragraphMD'}
                color={step === idx ? 'LIGHT_BASE_01' : 'INTENSE_COLOR_03'}
              >
                {`${idx + 1}. ${name}`}
              </Text>
            </Pressable>
          ))}
        </View>

        <SeparatorHorizontal
          mb="smaller"
          bgColor="BRAND_COMPLEMENT_02"
          height={1}
          width="100%"
        />

        <Text type="subtitleXXL" mb="nano">
          {currentName} — {product}
        </Text>

        <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm">
          <ScreenRenderer screen={screen} />
        </Box>
      </View>
    </ScrollView>
  );
}

const meta: Meta<typeof FullFlowDemo> = {
  title: 'SDUI/VoucherDemo',
  component: FullFlowDemo,
};

export default meta;

type Story = StoryObj<typeof meta>;

export const Form: Story = {
  render: () => <VoucherFormDemo />,
};

export const Summary: Story = {
  render: () => <VoucherSummaryDemo />,
};

export const Conclusion: Story = {
  render: () => <VoucherConclusionDemo />,
};

export const Rules: Story = {
  render: () => <VoucherRulesDemo />,
};

export const FullFlow: Story = {
  render: () => <FullFlowDemo />,
};

