const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1400, height: 900 } });

  await page.goto('http://localhost:6006/?path=/story/sdui-voucherdemo--form', { waitUntil: 'networkidle' });
  await page.waitForTimeout(3000);

  // Inject a MutationObserver on the panel to detect text changes
  await page.evaluate(() => {
    const panel = document.getElementById('storybook-panel-root');
    if (panel) {
      const observer = new MutationObserver((mutations) => {
        for (const m of mutations) {
          if (m.type === 'childList') {
            console.log('[PANEL-MUTATION] childList change');
          }
          if (m.type === 'characterData') {
            console.log('[PANEL-MUTATION] characterData:', m.target.textContent?.substring(0, 50));
          }
        }
      });
      observer.observe(panel, { childList: true, subtree: true, characterData: true });
      console.log('[PANEL-MUTATION] Observer installed');
    }
  });

  page.on('console', msg => {
    if (msg.text().includes('PANEL-MUTATION')) {
      console.log(msg.text());
    }
  });

  // Click Summary
  console.log('--- Clicking Summary ---');
  await page.locator('[data-item-id=\"sdui-voucherdemo--summary\"]').click();
  await page.waitForTimeout(3000);

  await browser.close();
})();
"
